// Phantom 接口 - 定义怪盗的基本能力
type Phantom interface {
    Steal() string
    Persona() string
}

// Joker 类型 - 隐式实现 Phantom 接口
type Joker struct {
    Name string
}

func (j Joker) Steal() string {
    return j.Name + " 执行了夺心行动！"
}

func (j Joker) Persona() string {
    return "Arsene! 来吧！"
}

// 不需要写: func (j Joker) implementsPhantom() {}
// Go 自动识别 Joker 实现了 Phantom 接口

// 基础能力接口
type Fighter interface {
    Attack()
}

type Healer interface {
    Heal()
}

type Buffer interface {
    Buff()
}

// 组合接口 - 全能型 Persona
type UltimatePersona interface {
    Fighter  // 内嵌攻击能力
    Healer   // 内嵌治疗能力
    Buffer   // 内嵌增益能力
}

func returnsPhantom() Phantom {
    var j *Joker  // j == nil
    return j      // 返回的接口值 != nil!
    // 接口有类型 (*Joker) 但值为 nil
}

// 正确的 nil 返回方式
func returnsNilPhantom() Phantom {
    return nil  // 类型为 nil，值也为 nil
}
